function validate(args, output) {
    const nums1 = args[0], nums2 = args[1];
    if (!Array.isArray(output) || output.length !== 2) return false;
    const a = output[0], b = output[1];
    if (!Array.isArray(a) || !Array.isArray(b)) return false;
    if (new Set(a).size !== a.length || new Set(b).size !== b.length) return false;
    const s1 = new Set(nums1), s2 = new Set(nums2);
    const expectedA = new Set([...s1].filter(x => !s2.has(x)));
    const expectedB = new Set([...s2].filter(x => !s1.has(x)));
    const setA = new Set(a), setB = new Set(b);
    if (setA.size !== expectedA.size || setB.size !== expectedB.size) return false;
    for (const x of setA) if (!expectedA.has(x)) return false;
    for (const x of setB) if (!expectedB.has(x)) return false;
    return true;
}

