var findDifference = function(nums1, nums2) {
    const s1 = new Set(nums1), s2 = new Set(nums2);
    const a = [...s1].filter(x => !s2.has(x)).sort((p, q) => p - q);
    const b = [...s2].filter(x => !s1.has(x)).sort((p, q) => p - q);
    return [a, b];
};
